        if depth > max_depth {
            return;
        }
        let kind = node.kind();
        let text = node.utf8_text(source.as_bytes()).unwrap_or("");
        let display = if text.len() > 80 {
            format!("{}...", &text[..77].replace('\n', "\\n"))
        } else {
            text.replace('\n', "\\n")
        };
        println!("{}{}: \"{}\"", "  ".repeat(depth), kind, display);
        for i in 0..node.named_child_count() {
            if let Some(child) = node.named_child(i) {
                traverse(child, source, depth + 1, max_depth);
            }
        }
