use tree_sitter::{Parser, Query, QueryCursor};
use streaming_iterator::StreamingIterator;

#[test]
fn debug_query_matching() {
    let source = r#"
package com.example.myapp;

import java.util.List;

public class HelloWorld implements java.io.Serializable {
    private String name;
    private int age;

    public HelloWorld(String name, int age) {
        this.name = name;
        this.age = age;
    }

    public static void main(String[] args) {
        System.out.println("Hello, World!");
        foo();
        bar.baz();
        new Thread().start();
    }

    public String getName() {
        return name;
    }
}

public interface Printable {
    void print();
}

public enum Color {
    RED, GREEN, BLUE;
}

public @interface MyAnnotation {
    String value() default "";
}
"#;
    let mut parser = Parser::new();
    let lang: tree_sitter::Language = tree_sitter_java::LANGUAGE.into();
    parser.set_language(&lang).unwrap();
    let tree = parser.parse(source, None).unwrap();

    // 测试修复后的 symbols.scm
    let symbols_query = std::include_str!("../../../queries/java/symbols.scm");
    println!("=== SYMBOLS.SCM ===\n{}", symbols_query);
    match Query::new(&lang, symbols_query) {
        Ok(q) => {
            let mut cursor = QueryCursor::new();
            let mut matches = cursor.matches(&q, tree.root_node(), source.as_bytes());
            let mut count = 0;
            while let Some(m) = matches.next() {
                count += 1;
                let mut sym_name = "";
                let mut capture_kind = "?";
                for capture in m.captures {
                    let name = q.capture_names()[capture.index as usize];
                    let text = capture.node.utf8_text(source.as_bytes()).unwrap_or("");
                    if name == "symbol.name" {
                        sym_name = text;
                    } else if name.starts_with("symbol.") {
                        capture_kind = name;
                    }
                }
                println!("  {}: {} = \"{}\"", count, capture_kind, sym_name);
            }
            println!("  Total symbols: {}\n", count);
        }
        Err(e) => {
            println!("  symbols.scm 编译错误: {:?}\n", e);
        }
    }

    // 测试修复后的 imports.scm
    let imports_query = std::include_str!("../../../queries/java/imports.scm");
    println!("=== IMPORTS.SCM ===\n{}", imports_query);
    match Query::new(&lang, imports_query) {
        Ok(q) => {
            let mut cursor = QueryCursor::new();
            let mut matches = cursor.matches(&q, tree.root_node(), source.as_bytes());
            let mut count = 0;
            while let Some(m) = matches.next() {
                count += 1;
                for capture in m.captures {
                    let name = q.capture_names()[capture.index as usize];
                    let text = capture.node.utf8_text(source.as_bytes()).unwrap_or("");
                    println!("  {}: [{}]=\"{}\"", count, name, text);
                }
            }
            println!("  Total import matches: {}\n", count);
        }
        Err(e) => {
            println!("  imports.scm 编译错误: {:?}\n", e);
        }
    }

    // 测试 calls.scm
    let calls_query = std::include_str!("../../../queries/java/calls.scm");
    println!("=== CALLS.SCM ===\n{}", calls_query);
    match Query::new(&lang, calls_query) {
        Ok(q) => {
            let mut cursor = QueryCursor::new();
            let mut matches = cursor.matches(&q, tree.root_node(), source.as_bytes());
            let mut count = 0;
            while let Some(m) = matches.next() {
                count += 1;
                for capture in m.captures {
                    let name = q.capture_names()[capture.index as usize];
                    let text = capture.node.utf8_text(source.as_bytes()).unwrap_or("");
                    println!("  {}: [{}]=\"{}\"", count, name, text);
                }
            }
            println!("  Total call matches: {}\n", count);
        }
        Err(e) => {
            println!("  calls.scm 编译错误: {:?}\n", e);
        }
    }
}

