use tree_sitter::{Parser, Query, QueryCursor};
use streaming_iterator::StreamingIterator;

#[test]
fn debug_query_matching() {
    let source = r#"
public class HelloWorld {
    public static void main(String[] args) {
        System.out.println("Hello, World!");
    }
}
"#;
    let mut parser = Parser::new();
    let lang: tree_sitter::Language = tree_sitter_java::LANGUAGE.into();
    parser.set_language(&lang).unwrap();
    let tree = parser.parse(source, None).unwrap();

    // 测试 symbols.scm 中类查询的简化版
    let queries = vec![
        // 原始类查询
        ("class (original)", r#"(class_declaration name: (identifier) @symbol.name) @symbol.class"#),
        // 测试只有 class_declaration 捕获
        ("class (bare)", r#"(class_declaration) @symbol.class"#),
        // 测试 name 字段直接捕获
        ("class (name field)", r#"(class_declaration) @symbol.class"#),
        // 方法声明
        ("method", r#"(method_declaration name: (identifier) @symbol.name) @symbol.method"#),
        // 字段
        ("field", r#"(field_declaration declarator: (variable_declarator name: (identifier) @symbol.name)) @symbol.field"#),
        // 接口
        ("interface", r#"(interface_declaration name: (identifier) @symbol.name) @symbol.interface"#),
        // 枚举
        ("enum", r#"(enum_declaration name: (identifier) @symbol.name) @symbol.enum"#),
        // 构造函数
        ("constructor", r#"(constructor_declaration name: (identifier) @symbol.name) @symbol.constructor"#),
        // 注解
        ("annotation", r#"(annotation_type_declaration name: (identifier) @symbol.name) @symbol.annotation"#),
        // import
        ("import", r#"(import_declaration name: (scoped_identifier) @import.path) @import"#),
        // package
        ("package", r#"(package_declaration name: (scoped_identifier) @import.package)"#),
    ];

    for (label, query_str) in &queries {
        println!("\n--- {} ---", label);
        println!("Query: {}", query_str);
        match Query::new(&lang, query_str) {
            Ok(q) => {
                let mut cursor = QueryCursor::new();
                let mut matches = cursor.matches(&q, tree.root_node(), source.as_bytes());
                let mut count = 0;
                while let Some(m) = matches.next() {
                    count += 1;
                    print!("  Match {}: ", count);
                    for capture in m.captures {
                        let name = q.capture_names()[capture.index as usize];
                        let text = capture.node.utf8_text(source.as_bytes()).unwrap_or("");
                        print!("[{}]=\"{}\" ", name, text);
                    }
                    println!();
                }
                if count == 0 {
                    println!("  (no matches)");
                }
            }
            Err(e) => {
                println!("  Query error: {:?}", e);
            }
        }
    }

    // 测试完整的 symbols.scm 内容
    println!("\n\n=== FULL SYMBOLS.SCM ===");
    let full_query = std::include_str!("../../../queries/java/symbols.scm");
    println!("{}", full_query);
    match Query::new(&lang, full_query) {
        Ok(q) => {
            let mut cursor = QueryCursor::new();
            let mut matches = cursor.matches(&q, tree.root_node(), source.as_bytes());
            let mut count = 0;
            while let Some(m) = matches.next() {
                count += 1;
                print!("  Match {}: ", count);
                for capture in m.captures {
                    let name = q.capture_names()[capture.index as usize];
                    let text = capture.node.utf8_text(source.as_bytes()).unwrap_or("");
                    print!("[{}]=\"{}\" ", name, text);
                }
                println!();
            }
            if count == 0 {
                println!("  (no matches)");
            }
        }
        Err(e) => {
            println!("  Query error: {:?}", e);
        }
    }
}

