fn extract_calls(&self, tree: &Tree, source: &str, file_path: &Path) -> Vec<CallSite> {
    let queries = load_java_queries();
    let file_path_str = file_path.to_string_lossy().to_string();
    let mut results = Vec::new();

    let query = match Query::new(&self.language, &queries.calls) {
        Ok(q) => q,
        Err(_) => return results,
    };

    let mut cursor = QueryCursor::new();
    let mut matches = cursor.matches(&query, tree.root_node(), source.as_bytes());

    // 临时存储：(行号, 列号) -> (callee_name, call_type, location)
    // 用于去重：call.method 优先于 call（更具体的匹配）
    use std::collections::HashMap;
    let mut seen: HashMap<(u64, u64), (String, CallType, SourceLocation)> = HashMap::new();

    while let Some(m) = matches.next() {
        let mut callee_name = String::new();
        let mut call_type = CallType::Direct;
        let mut location = SourceLocation {
            file_path: file_path_str.clone(),
            line: 0,
            column: 0,
            end_line: 0,
            end_column: 0,
        };
        let mut capture_kind = "";

        for capture in m.captures {
            let node = capture.node;
            let capture_name = query.capture_names()[capture.index as usize];

            match capture_name {
                "call.name" => {
                    callee_name = self.node_text(node, source).to_string();
                }
                "call" => {
                    location = self.node_to_location(node);
                    capture_kind = "call";
                }
                "call.method" => {
                    call_type = CallType::Virtual; // Java 对象方法调用可能通过动态分发
                    location = self.node_to_location(node);
                    capture_kind = "call.method";
                }
                "call.constructor" => {
                    call_type = CallType::Direct;
                    location = self.node_to_location(node);
                    capture_kind = "call.constructor";
                }
                _ => {}
            }
        }

        if !callee_name.is_empty() && location.line > 0 {
            let key = (location.line, location.column);
            // call.method 优先于 call（更具体的匹配）
            if let Some(existing) = seen.get(&key) {
                if capture_kind == "call.method" && existing.1 == CallType::Direct {
                    // 用更具体的 call.method 替换 call
                    seen.insert(key, (callee_name, call_type, location));
                }
            } else {
                seen.insert(key, (callee_name, call_type, location));
            }
        }
    }

    // 转为结果 Vec
    for (_, (callee_name, call_type, location)) in seen {
        results.push(CallSite {
            caller_id: String::new(),
            callee_name,
            location,
            call_type,
            confidence: 0.9,
        });
    }

    results
}

