use tree_sitter::Parser;

#[test]
fn debug_object_creation() {
    let source = "class X { void m() { new Thread().start(); } }";
    let mut parser = Parser::new();
    let lang: tree_sitter::Language = tree_sitter_java::LANGUAGE.into();
    parser.set_language(&lang).unwrap();
    let tree = parser.parse(source, None).unwrap();

    fn traverse(node: tree_sitter::Node, source: &str, depth: usize) {
        let indent = "  ".repeat(depth);
        let kind = node.kind();
        let text = node.utf8_text(source.as_bytes()).unwrap_or("");
        let display = text.replace('\n', "\\n");
        println!("{}{}: \"{}\"", indent, kind, display);
        for i in 0..node.named_child_count() {
            if let Some(child) = node.named_child(i) {
                traverse(child, source, depth + 1);
            }
        }
    }
    traverse(tree.root_node(), source, 0);

    // 测试查询
    use tree_sitter::{Query, QueryCursor};
    use streaming_iterator::StreamingIterator;

    let queries = vec![
        ("type_identifier", r#"(object_creation_expression (type_identifier) @call.name) @call.constructor"#),
        ("_simple_type wildcard", r#"(object_creation_expression type: (_) @call.name) @call.constructor"#),
        ("any child", r#"(object_creation_expression (_) @call.name) @call.constructor"#),
    ];

    for (label, q_str) in queries {
        println!("\n=== {} ===", label);
        match Query::new(&lang, q_str) {
            Ok(q) => {
                let mut cursor = QueryCursor::new();
                let mut m = cursor.matches(&q, tree.root_node(), source.as_bytes());
                let mut count = 0;
                while let Some(match_) = m.next() {
                    count += 1;
                    for c in match_.captures {
                        let name = q.capture_names()[c.index as usize];
                        let text = c.node.utf8_text(source.as_bytes()).unwrap_or("");
                        println!("  [{}]=\"{}\"", name, text);
                    }
                }
                if count == 0 { println!("  (no matches)"); }
            }
            Err(e) => println!("  Error: {:?}", e),
        }
    }
}

