#[test]
fn test_dump_constructor_and_calls_ast() {
    let source = r#"public class Point { public Point(int x) { } public void run() { new Thread().start(); foo(); } }"#;
    let parser = JavaParser::new();
    let tree = parser.parse(source).expect("解析失败");

    // 用 Query 确认关键节点存在
    use tree_sitter::Query;
    let lang = tree_sitter_java::LANGUAGE.into();
    let check_ctor = r#"(constructor_declaration) @ctor"#;
    let check_new = r#"(object_creation_expression) @new"#;
    let (has_ctor, has_new) = (|| -> bool {
        let q = Query::new(&lang, check_ctor).ok()?;
        let mut cursor = tree_sitter::QueryCursor::new();
        let mut m = cursor.matches(&q, tree.root_node(), source.as_bytes());
        while let Some(_) = m.next() { return true; }
        false
    })(), (|| -> bool {
        let q = Query::new(&lang, check_new).ok()?;
        let mut cursor = tree_sitter::QueryCursor::new();
        let mut m = cursor.matches(&q, tree.root_node(), source.as_bytes());
        while let Some(_) = m.next() { return true; }
        false
    })();
    assert!(has_ctor, "应包含 constructor_declaration");
    assert!(has_new, "应包含 object_creation_expression");
}

